import{_ as r,o as e,c as a,ai as l}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"React 开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/react-projects.md","filePath":"open-source/react-projects.md"}'),i={name:"open-source/react-projects.md"};function o(s,t,h,n,u,c){return e(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="react-开源项目" tabindex="-1">React 开源项目 <a class="header-anchor" href="#react-开源项目" aria-label="Permalink to “React 开源项目”">​</a></h1><p>本页面精选了优秀的React开源项目，包括框架、组件库、工具、应用等。</p><h2 id="核心框架" tabindex="-1">核心框架 <a class="header-anchor" href="#核心框架" aria-label="Permalink to “核心框架”">​</a></h2><ul><li><p><strong>React</strong>：用于构建用户界面的JavaScript库</p><ul><li>GitHub: <a href="https://github.com/facebook/react" target="_blank" rel="noreferrer">https://github.com/facebook/react</a></li><li>特点: 组件化、声明式、虚拟DOM</li></ul></li><li><p><strong>React 18</strong>：最新稳定版本</p><ul><li>新特性: 并发渲染、Suspense、自动批处理</li></ul></li></ul><h2 id="ui-框架与组件库" tabindex="-1">UI 框架与组件库 <a class="header-anchor" href="#ui-框架与组件库" aria-label="Permalink to “UI 框架与组件库”">​</a></h2><h3 id="桌面端组件库" tabindex="-1">桌面端组件库 <a class="header-anchor" href="#桌面端组件库" aria-label="Permalink to “桌面端组件库”">​</a></h3><ul><li><p><strong>Material-UI (MUI)</strong>：Material Design组件库</p><ul><li>GitHub: <a href="https://github.com/mui/material-ui" target="_blank" rel="noreferrer">https://github.com/mui/material-ui</a></li><li>特点: Material Design、主题定制、国际化</li></ul></li><li><p><strong>Ant Design</strong>：企业级UI设计语言</p><ul><li>GitHub: <a href="https://github.com/ant-design/ant-design" target="_blank" rel="noreferrer">https://github.com/ant-design/ant-design</a></li><li>特点: 企业级、完整组件、设计规范</li></ul></li><li><p><strong>Chakra UI</strong>：简单灵活的组件库</p><ul><li>GitHub: <a href="https://github.com/chakra-ui/chakra-ui" target="_blank" rel="noreferrer">https://github.com/chakra-ui/chakra-ui</a></li><li>特点: 组合式API、主题定制、暗色模式</li></ul></li><li><p><strong>React Bootstrap</strong>：Bootstrap组件的React实现</p><ul><li>GitHub: <a href="https://github.com/react-bootstrap/react-bootstrap" target="_blank" rel="noreferrer">https://github.com/react-bootstrap/react-bootstrap</a></li><li>特点: Bootstrap兼容、响应式设计</li></ul></li></ul><h3 id="移动端组件库" tabindex="-1">移动端组件库 <a class="header-anchor" href="#移动端组件库" aria-label="Permalink to “移动端组件库”">​</a></h3><ul><li><p><strong>React Native Elements</strong>：跨平台UI工具包</p><ul><li>GitHub: <a href="https://github.com/react-native-elements/react-native-elements" target="_blank" rel="noreferrer">https://github.com/react-native-elements/react-native-elements</a></li><li>功能: 丰富的组件、主题支持</li></ul></li><li><p><strong>NativeBase</strong>：移动端组件库</p><ul><li>GitHub: <a href="https://github.com/GeekyAnts/NativeBase" target="_blank" rel="noreferrer">https://github.com/GeekyAnts/NativeBase</a></li><li>特点: 通用组件、平台适配</li></ul></li></ul><h2 id="路由与状态管理" tabindex="-1">路由与状态管理 <a class="header-anchor" href="#路由与状态管理" aria-label="Permalink to “路由与状态管理”">​</a></h2><h3 id="路由" tabindex="-1">路由 <a class="header-anchor" href="#路由" aria-label="Permalink to “路由”">​</a></h3><ul><li><p><strong>React Router</strong>：声明式路由</p><ul><li>GitHub: <a href="https://github.com/remix-run/react-router" target="_blank" rel="noreferrer">https://github.com/remix-run/react-router</a></li><li>功能: 客户端路由、代码分割、嵌套路由</li></ul></li><li><p><strong>React Router v6</strong>：最新版本</p><ul><li>新特性: 更简单的API、更好的TypeScript支持</li></ul></li></ul><h3 id="状态管理" tabindex="-1">状态管理 <a class="header-anchor" href="#状态管理" aria-label="Permalink to “状态管理”">​</a></h3><ul><li><p><strong>Redux</strong>：可预测的状态容器</p><ul><li>GitHub: <a href="https://github.com/reduxjs/redux" target="_blank" rel="noreferrer">https://github.com/reduxjs/redux</a></li><li>特点: 单向数据流、中间件、时间旅行调试</li></ul></li><li><p><strong>Redux Toolkit</strong>：Redux官方推荐工具包</p><ul><li>GitHub: <a href="https://github.com/reduxjs/redux-toolkit" target="_blank" rel="noreferrer">https://github.com/reduxjs/redux-toolkit</a></li><li>功能: 简化Redux、减少样板代码</li></ul></li><li><p><strong>Zustand</strong>：轻量级状态管理</p><ul><li>GitHub: <a href="https://github.com/pmndrs/zustand" target="_blank" rel="noreferrer">https://github.com/pmndrs/zustand</a></li><li>特点: 简单API、TypeScript友好</li></ul></li><li><p><strong>Recoil</strong>：React状态管理库</p><ul><li>GitHub: <a href="https://github.com/facebookexperimental/Recoil" target="_blank" rel="noreferrer">https://github.com/facebookexperimental/Recoil</a></li><li>功能: 原子化状态、派生状态</li></ul></li></ul><h2 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h2><h3 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h3><ul><li><p><strong>Create React App</strong>：官方脚手架</p><ul><li>GitHub: <a href="https://github.com/facebook/create-react-app" target="_blank" rel="noreferrer">https://github.com/facebook/create-react-app</a></li><li>功能: 零配置、快速启动</li></ul></li><li><p><strong>Vite</strong>：下一代构建工具</p><ul><li>GitHub: <a href="https://github.com/vitejs/vite" target="_blank" rel="noreferrer">https://github.com/vitejs/vite</a></li><li>特点: 快速启动、热重载</li></ul></li><li><p><strong>Next.js</strong>：React的全栈框架</p><ul><li>GitHub: <a href="https://github.com/vercel/next.js" target="_blank" rel="noreferrer">https://github.com/vercel/next.js</a></li><li>功能: SSR、静态生成、API路由</li></ul></li><li><p><strong>Gatsby</strong>：静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/gatsbyjs/gatsby" target="_blank" rel="noreferrer">https://github.com/gatsbyjs/gatsby</a></li><li>功能: GraphQL、PWA、性能优化</li></ul></li></ul><h3 id="开发辅助" tabindex="-1">开发辅助 <a class="header-anchor" href="#开发辅助" aria-label="Permalink to “开发辅助”">​</a></h3><ul><li><p><strong>React DevTools</strong>：浏览器调试工具</p><ul><li>GitHub: <a href="https://github.com/facebook/react-devtools" target="_blank" rel="noreferrer">https://github.com/facebook/react-devtools</a></li><li>功能: 组件检查、性能分析</li></ul></li><li><p><strong>Storybook</strong>：UI组件开发环境</p><ul><li>GitHub: <a href="https://github.com/storybookjs/storybook" target="_blank" rel="noreferrer">https://github.com/storybookjs/storybook</a></li><li>功能: 组件文档、交互测试</li></ul></li></ul><h2 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h2><h3 id="http客户端" tabindex="-1">HTTP客户端 <a class="header-anchor" href="#http客户端" aria-label="Permalink to “HTTP客户端”">​</a></h3><ul><li><p><strong>Axios</strong>：Promise-based HTTP客户端</p><ul><li>GitHub: <a href="https://github.com/axios/axios" target="_blank" rel="noreferrer">https://github.com/axios/axios</a></li><li>功能: HTTP请求、拦截器</li></ul></li><li><p><strong>React Query</strong>：数据获取和缓存</p><ul><li>GitHub: <a href="https://github.com/tannerlinsley/react-query" target="_blank" rel="noreferrer">https://github.com/tannerlinsley/react-query</a></li><li>功能: 服务器状态管理、缓存、同步</li></ul></li></ul><h3 id="表单处理" tabindex="-1">表单处理 <a class="header-anchor" href="#表单处理" aria-label="Permalink to “表单处理”">​</a></h3><ul><li><p><strong>React Hook Form</strong>：高性能表单库</p><ul><li>GitHub: <a href="https://github.com/react-hook-form/react-hook-form" target="_blank" rel="noreferrer">https://github.com/react-hook-form/react-hook-form</a></li><li>特点: 最小重渲染、无依赖</li></ul></li><li><p><strong>Formik</strong>：React表单库</p><ul><li>GitHub: <a href="https://github.com/formium/formik" target="_blank" rel="noreferrer">https://github.com/formium/formik</a></li><li>功能: 表单状态管理、验证</li></ul></li></ul><h3 id="图表库" tabindex="-1">图表库 <a class="header-anchor" href="#图表库" aria-label="Permalink to “图表库”">​</a></h3><ul><li><p><strong>Recharts</strong>：基于React的图表库</p><ul><li>GitHub: <a href="https://github.com/recharts/recharts" target="_blank" rel="noreferrer">https://github.com/recharts/recharts</a></li><li>功能: 多种图表类型、响应式</li></ul></li><li><p><strong>Victory</strong>：模块化图表组件</p><ul><li>GitHub: <a href="https://github.com/FormidableLabs/victory" target="_blank" rel="noreferrer">https://github.com/FormidableLabs/victory</a></li><li>特点: 可组合、动画支持</li></ul></li></ul><h3 id="动画库" tabindex="-1">动画库 <a class="header-anchor" href="#动画库" aria-label="Permalink to “动画库”">​</a></h3><ul><li><p><strong>Framer Motion</strong>：React动画库</p><ul><li>GitHub: <a href="https://github.com/framer/motion" target="_blank" rel="noreferrer">https://github.com/framer/motion</a></li><li>功能: 手势、布局动画、拖拽</li></ul></li><li><p><strong>React Spring</strong>：基于弹簧物理的动画库</p><ul><li>GitHub: <a href="https://github.com/pmndrs/react-spring" target="_blank" rel="noreferrer">https://github.com/pmndrs/react-spring</a></li><li>特点: 流畅动画、自然交互</li></ul></li></ul><h3 id="其他工具" tabindex="-1">其他工具 <a class="header-anchor" href="#其他工具" aria-label="Permalink to “其他工具”">​</a></h3><ul><li><p><strong>React Hooks</strong>：官方Hooks库</p><ul><li>GitHub: <a href="https://github.com/facebook/react" target="_blank" rel="noreferrer">https://github.com/facebook/react</a></li><li>功能: useState、useEffect等</li></ul></li><li><p><strong>React Router</strong>：路由库</p><ul><li>GitHub: <a href="https://github.com/remix-run/react-router" target="_blank" rel="noreferrer">https://github.com/remix-run/react-router</a></li><li>功能: 声明式路由</li></ul></li></ul><h2 id="应用项目" tabindex="-1">应用项目 <a class="header-anchor" href="#应用项目" aria-label="Permalink to “应用项目”">​</a></h2><h3 id="后台管理系统" tabindex="-1">后台管理系统 <a class="header-anchor" href="#后台管理系统" aria-label="Permalink to “后台管理系统”">​</a></h3><ul><li><p><strong>React Admin</strong>：前端管理框架</p><ul><li>GitHub: <a href="https://github.com/marmelab/react-admin" target="_blank" rel="noreferrer">https://github.com/marmelab/react-admin</a></li><li>功能: CRUD操作、数据提供者</li></ul></li><li><p><strong>AdminJS</strong>：自动生成管理面板</p><ul><li>GitHub: <a href="https://github.com/SoftwareBrothers/adminjs" target="_blank" rel="noreferrer">https://github.com/SoftwareBrothers/adminjs</a></li><li>功能: 自动生成UI、插件系统</li></ul></li></ul><h3 id="博客-cms系统" tabindex="-1">博客/CMS系统 <a class="header-anchor" href="#博客-cms系统" aria-label="Permalink to “博客/CMS系统”">​</a></h3><ul><li><p><strong>Gatsby</strong>：静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/gatsbyjs/gatsby" target="_blank" rel="noreferrer">https://github.com/gatsbyjs/gatsby</a></li><li>功能: Markdown、GraphQL</li></ul></li><li><p><strong>Strapi</strong>：Headless CMS</p><ul><li>GitHub: <a href="https://github.com/strapi/strapi" target="_blank" rel="noreferrer">https://github.com/strapi/strapi</a></li><li>功能: API优先、插件丰富</li></ul></li></ul><h3 id="电商应用" tabindex="-1">电商应用 <a class="header-anchor" href="#电商应用" aria-label="Permalink to “电商应用”">​</a></h3><ul><li><strong>Commerce.js</strong>：无头电商 <ul><li>GitHub: <a href="https://github.com/chec/commerce.js" target="_blank" rel="noreferrer">https://github.com/chec/commerce.js</a></li><li>功能: 购物车、结账、库存</li></ul></li></ul><h3 id="聊天应用" tabindex="-1">聊天应用 <a class="header-anchor" href="#聊天应用" aria-label="Permalink to “聊天应用”">​</a></h3><ul><li><strong>React Chat Widget</strong>：聊天组件 <ul><li>GitHub: <a href="https://github.com/Wolox/react-chat-widget" target="_blank" rel="noreferrer">https://github.com/Wolox/react-chat-widget</a></li><li>功能: 实时聊天、自定义样式</li></ul></li></ul><h2 id="服务端渲染" tabindex="-1">服务端渲染 <a class="header-anchor" href="#服务端渲染" aria-label="Permalink to “服务端渲染”">​</a></h2><ul><li><p><strong>Next.js</strong>：React SSR框架</p><ul><li>GitHub: <a href="https://github.com/vercel/next.js" target="_blank" rel="noreferrer">https://github.com/vercel/next.js</a></li><li>功能: 服务器端渲染、静态生成</li></ul></li><li><p><strong>Razzle</strong>：通用应用框架</p><ul><li>GitHub: <a href="https://github.com/jaredpalmer/razzle" target="_blank" rel="noreferrer">https://github.com/jaredpalmer/razzle</a></li><li>功能: 零配置SSR</li></ul></li></ul><h2 id="移动端框架" tabindex="-1">移动端框架 <a class="header-anchor" href="#移动端框架" aria-label="Permalink to “移动端框架”">​</a></h2><ul><li><p><strong>React Native</strong>：构建原生移动应用</p><ul><li>GitHub: <a href="https://github.com/facebook/react-native" target="_blank" rel="noreferrer">https://github.com/facebook/react-native</a></li><li>功能: 跨平台开发、原生性能</li></ul></li><li><p><strong>Expo</strong>：React Native工具链</p><ul><li>GitHub: <a href="https://github.com/expo/expo" target="_blank" rel="noreferrer">https://github.com/expo/expo</a></li><li>功能: 简化开发、云构建</li></ul></li></ul><h2 id="测试框架" tabindex="-1">测试框架 <a class="header-anchor" href="#测试框架" aria-label="Permalink to “测试框架”">​</a></h2><ul><li><p><strong>Jest</strong>：JavaScript测试框架</p><ul><li>GitHub: <a href="https://github.com/facebook/jest" target="_blank" rel="noreferrer">https://github.com/facebook/jest</a></li><li>功能: 零配置、快照测试</li></ul></li><li><p><strong>React Testing Library</strong>：React组件测试</p><ul><li>GitHub: <a href="https://github.com/testing-library/react-testing-library" target="_blank" rel="noreferrer">https://github.com/testing-library/react-testing-library</a></li><li>功能: 行为驱动测试</li></ul></li><li><p><strong>Cypress</strong>：端到端测试</p><ul><li>GitHub: <a href="https://github.com/cypress-io/cypress" target="_blank" rel="noreferrer">https://github.com/cypress-io/cypress</a></li><li>功能: 实时重载、调试友好</li></ul></li></ul>',45)])])}const p=r(i,[["render",o]]);export{g as __pageData,p as default};
